/**
 * SubjectType
 *
 * 条目类型
 * - `1` 为 书籍
 * - `2` 为 动画
 * - `3` 为 音乐
 * - `4` 为 游戏
 * - `6` 为 三次元
 *
 * 没有 `5`
 */
export type SubjectType = 1 | 2 | 3 | 4 | 6;

/**
 * SubjectBookCategory
 *
 * 书籍类型
 * - `0` 为 其他
 * - `1001` 为 漫画
 * - `1002` 为 小说
 * - `1003` 为 画集
 */
export type SubjectBookCategory = 0 | 1001 | 1002 | 1003;

/**
 * SubjectAnimeCategory
 *
 * 动画类型
 * - `0` 为 其他
 * - `1` 为 TV
 * - `2` 为 OVA
 * - `3` 为 Movie
 * - `5` 为 WEB
 */
export type SubjectAnimeCategory = 0 | 1 | 2 | 3 | 5;

/**
 * SubjectGameCategory
 *
 * 游戏类型
 * - `0` 为 其他
 * - `4001` 为 游戏
 * - `4002` 为 软件
 * - `4003` 为 扩展包
 * - `4005` 为 桌游
 */
export type SubjectGameCategory = 0 | 4001 | 4003 | 4002 | 4005;

/**
 * SubjectRealCategory
 *
 * 电影类型
 * - `0` 为 其他
 * - `1` 为 日剧
 * - `2` 为 欧美剧
 * - `3` 为 华语剧
 * - `6001` 为 电视剧
 * - `6002` 为 电影
 * - `6003` 为 演出
 * - `6004` 为 综艺
 */
export type SubjectRealCategory = 0 | 1 | 2 | 3 | 6001 | 6002 | 6003 | 6004;

export type SubjectCategory = SubjectBookCategory | SubjectAnimeCategory | SubjectGameCategory | SubjectRealCategory;

/**
 * UserSubjectCollection
 */
export type UserSubjectCollection = {
    /**
     * Subject ID
     */
    subject_id: number;
    subject_type: SubjectType;
    /**
     * Rate
     */
    rate: number;
    type: SubjectCollectionType;
    /**
     * Comment
     */
    comment?: string;
    /**
     * Tags
     */
    tags: Array<string>;
    /**
     * Ep Status
     */
    ep_status: number;
    /**
     * Vol Status
     */
    vol_status: number;
    /**
     * Updated At
     *
     * 本时间并不代表条目的收藏时间。修改评分，评价，章节观看状态等收藏信息时未更新此时间是一个 bug。请不要依赖此特性
     */
    updated_at: string;
    /**
     * Private
     */
    private: boolean;
    subject?: SlimSubject;
};

/**
 * UserSubjectCollectionModifyPayload
 *
 * 所有的字段均可选
 */
export type UserSubjectCollectionModifyPayload = {
    /**
     * 修改条目收藏类型
     */
    type?: SubjectCollectionType;
    /**
     * 评分，`0` 表示删除评分
     */
    rate?: number;
    /**
     * 只能用于修改书籍条目进度
     */
    ep_status?: number;
    /**
     * 只能用于修改书籍条目进度
     */
    vol_status?: number;
    /**
     * 评价
     */
    comment?: string;
    /**
     * 仅自己可见
     */
    private?: boolean;
    /**
     * 标签
     *
     * 不传或者 `null` 都会被忽略，传 `[]` 则会删除所有 tag。
     */
    tags?: Array<string>;
};

