export type SearchSubjectsData = {
    body?: {
        keyword: string;
        /**
         * 排序规则
         *
         * - `match` meilisearch 的默认排序，按照匹配程度
         * - `heat` 收藏人数
         * - `rank` 排名由高到低
         * - `score` 评分
         *
         */
        sort?: 'match' | 'heat' | 'rank' | 'score';
        /**
         * 不同条件之间是 `且` 的关系
         */
        filter?: {
            /**
             * 条目类型，参照 `SubjectType` enum，多值之间为 `或` 的关系。
             */
            type?: Array<SubjectType>;
            /**
             * 公共标签。多个值之间为 `且` 关系。可以用 `-` 排除标签。比如 `-科幻` 可以排除科幻标签。
             */
            meta_tags?: Array<string>;
            /**
             * 标签，可以多次出现。多值之间为 `且` 关系。
             */
            tag?: Array<string>;
            /**
             * 播出日期/发售日期，日期必需为 `YYYY-MM-DD` 格式。多值之间为 `且` 关系。
             */
            air_date?: Array<string>;
            /**
             * 用于搜索指定评分的条目，多值之间为 `且` 关系。
             */
            rating?: Array<string>;
            /**
             * 用于按照评分人数筛选条目，多值之间为 `且` 关系，格式与 `rating` 相同。
             */
            rating_count?: Array<string>;
            /**
             * 用于搜索指定排名的条目，多值之间为 `且` 关系。
             */
            rank?: Array<string>;
            /**
             * 无权限的用户会直接忽略此字段，不会返回R18条目。
             *
             * 默认或者 `null` 会返回包含 R18 的所有搜索结果。
             *
             * `true` 只会返回 R18 条目。
             *
             * `false` 只会返回非 R18 条目。
             *
             */
            nsfw?: boolean;
        };
    };
    path?: never;
    query?: {
        /**
         * 分页参数
         */
        limit?: number;
        /**
         * 分页参数
         */
        offset?: number;
    };
    url: '/v0/search/subjects';
};

export type SearchSubjectsResponses = {
    /**
     * 返回搜索结果
     */
    200: PagedSubject;
};

export type SearchSubjectsResponse = SearchSubjectsResponses[keyof SearchSubjectsResponses];

